const fs = require\('fs'\);
const path = require\('path'\);

const base = 'D:/programs/33Metro/bot/public/assets/enemy';

const entries = [
  { enemy: 'goblin',        dir: 'goblin/goblin_black',        anims: ['idle', 'hit'] },
  { enemy: 'ninja',         dir: 'ninja/yellow_ninja',          anims: ['idle', 'attack'] },
  { enemy: 'necromancer',   dir: 'necromancer/necromancer_1',   anims: ['idle', 'attack'] },
  { enemy: 'night_born',    dir: 'night_born/night_born_1',     anims: ['idle', 'attack'] },
  { enemy: 'blue_witch',    dir: 'blue_witch/v0',               anims: ['idle', 'attack_1', 'attack_2'] },
  { enemy: 'king',          dir: 'king/v0',                     anims: ['idle', 'attack_1', 'attack_2'] },
  { enemy: 'knight_enemy',  dir: 'knight_enemy/v0',             anims: ['idle', 'attack_1'] },
  { enemy: 'necromancer_2', dir: 'necromancer_2/v0',            anims: ['idle', 'attack_1'] },
  { enemy: 'orc',           dir: 'orc/v0',                      anims: ['idle', 'attack_1', 'attack_2'] },
  { enemy: 'paladin',       dir: 'paladin/v0',                  anims: ['idle', 'attack_1'] },
  { enemy: 'ronin_enemy',   dir: 'ronin_enemy/v0',              anims: ['idle', 'attack_1', 'attack_2'] },
  { enemy: 'reaper',        dir: 'reaper/v0',                   anims: ['idle', 'attack_1', 'attack_2'] },
  { enemy: 'soldier',       dir: 'soldier/v0',                  anims: ['idle', 'attack_1', 'attack_2', 'attack_3'] },
  { enemy: 'striker',       dir: 'striker/v0',                  anims: ['idle', 'attack_1', 'attack_2'] },
];

// Also check for hurt.json in each directory
for \(const e of entries\) {
  const hurtPath = path.join\(base, e.dir, 'hurt.json'\);
  if \(fs.existsSync\(hurtPath\) && !e.anims.includes\('hurt'\)\) {
    e.anims.push\('hurt'\);
  }
}

const rows = [];

for \(const e of entries\) {
  for \(const anim of e.anims\) {
    const filePath = path.join\(base, e.dir, anim + '.json'\);
    try {
      const data = JSON.parse\(fs.readFileSync\(filePath, 'utf8'\)\);
      // Aseprite JSON format: frames can be object or array
      let firstFrame;
      if \(data.frames\) {
        if \(Array.isArray\(data.frames\)\) {
          firstFrame = data.frames[0];
        } else {
          // Object keyed by frame name
          const keys = Object.keys\(data.frames\);
          firstFrame = data.frames[keys[0]];
        }
      }
      const w = firstFrame.sourceSize?.w ?? firstFrame.frame?.w ?? '?';
      const h = firstFrame.sourceSize?.h ?? firstFrame.frame?.h ?? '?';
      const fw = firstFrame.frame?.w ?? '?';
      const fh = firstFrame.frame?.h ?? '?';
      const frameCount = Array.isArray\(data.frames\) ? data.frames.length : Object.keys\(data.frames\).length;
      rows.push\({ enemy: e.enemy, anim, w, h, fw, fh, frameCount }\);
    } catch \(err\) {
      rows.push\({ enemy: e.enemy, anim, w: 'ERR', h: 'ERR', fw: 'ERR', fh: 'ERR', frameCount: '?' }\);
    }
  }
}

// Print table
const colWidths = { enemy: 16, anim: 12, w: 6, h: 6, fw: 6, fh: 6, frames: 6 };
const header = 'enemy'.padEnd\(colWidths.enemy\) + '| ' +
               'anim'.padEnd\(colWidths.anim\) + '| ' +
               'w'.padStart\(colWidths.w\) + ' | ' +
               'h'.padStart\(colWidths.h\) + ' | ' +
               'fw'.padStart\(colWidths.fw\) + ' | ' +
               'fh'.padStart\(colWidths.fh\) + ' | ' +
               'frames'.padStart\(colWidths.frames\);
console.log\(header\);
console.log\('-'.repeat\(header.length\)\);

let prevEnemy = '';
for \(const r of rows\) {
  if \(prevEnemy && prevEnemy !== r.enemy\) {
    console.log\('-'.repeat\(header.length\)\);
  }
  prevEnemy = r.enemy;
  console.log\(
    r.enemy.padEnd\(colWidths.enemy\) + '| ' +
    r.anim.padEnd\(colWidths.anim\) + '| ' +
    String\(r.w\).padStart\(colWidths.w\) + ' | ' +
    String\(r.h\).padStart\(colWidths.h\) + ' | ' +
    String\(r.fw\).padStart\(colWidths.fw\) + ' | ' +
    String\(r.fh\).padStart\(colWidths.fh\) + ' | ' +
    String\(r.frameCount\).padStart\(colWidths.frames\)
  \);
}

// Summary: highlight mismatches
console.log\('\\n\\n=== MISMATCHES \(idle vs attack/hit frame sizes\) ===\\n'\);

const grouped = {};
for \(const r of rows\) {
  if \(!grouped[r.enemy]\) grouped[r.enemy] = {};
  grouped[r.enemy][r.anim] = r;
}

let anyMismatch = false;
for \(const [enemy, anims] of Object.entries\(grouped\)\) {
  const idle = anims['idle'];
  if \(!idle\) continue;
  for \(const [animName, data] of Object.entries\(anims\)\) {
    if \(animName === 'idle'\) continue;
    if \(data.w !== idle.w || data.h !== idle.h\) {
      anyMismatch = true;
      console.log\(`${enemy}: idle\(${idle.w}x${idle.h}\) != ${animName}\(${data.w}x${data.h}\)`\);
    }
  }
}

if \(!anyMismatch\) {
  console.log\('No mismatches found - all enemies have consistent frame sizes.'\);
}
SCRIPT)

