/**
 * Skill-tree topology analyzer.
 *
 * Metrics:
 *   1. Node count by type
 *   2. Total edge count
 *   3. Nodes per class
 *   4. BFS connectivity: can every node reach every other node in ≤60 steps
 *      \(without passing through start nodes of other classes\)?
 *   5. Max BFS distance between any two nodes \(same constraint\)
 */

import { buildSkillTree, CLASS_IDS } from './skill-tree.ts';

const tree = buildSkillTree\(\);
const { nodes, edges } = tree;

// ── 1. Node count by type ────────────────────────────────

const byType = {};
for \(const n of nodes\) {
  byType[n.type] = \(byType[n.type] || 0\) + 1;
}
console.log\('=== 1. Node count by type ==='\);
for \(const [t, c] of Object.entries\(byType\).sort\(\)\) {
  console.log\(`  ${t}: ${c}`\);
}
console.log\(`  TOTAL: ${nodes.length}`\);

// ── 2. Edge count ────────────────────────────────────────

console.log\(`\\n=== 2. Total edge count ===`\);
console.log\(`  ${edges.length}`\);

// ── 3. Nodes per class ───────────────────────────────────

const byClass = {};
for \(const n of nodes\) {
  byClass[n.classAffinity] = \(byClass[n.classAffinity] || 0\) + 1;
}
console.log\('\\n=== 3. Nodes per class ==='\);
for \(const [cls, c] of Object.entries\(byClass\).sort\(\)\) {
  console.log\(`  ${cls}: ${c}`\);
}

// ── Build adjacency list \(id → Set<id>\) ─────────────────

const adj = new Map\(\);
for \(const n of nodes\) {
  adj.set\(n.id, new Set\(n.connections\)\);
}

// Map id → node for quick lookups
const nodeById = new Map\(\);
for \(const n of nodes\) {
  nodeById.set\(n.id, n\);
}

// Collect start-node ids per class
const startIds = new Map\(\);     // classId → nodeId
const startIdSet = new Set\(\);   // all start node ids
for \(const n of nodes\) {
  if \(n.type === 'start'\) {
    startIds.set\(n.classAffinity, n.id\);
    startIdSet.add\(n.id\);
  }
}

// ── BFS with "no foreign start" constraint ───────────────
// From `srcId`, BFS outward. We may NOT traverse through a start node that
// belongs to a *different* class than the source's class.
// Returns Map<id, distance>.

function bfsConstrained\(srcId\) {
  const srcClass = nodeById.get\(srcId\).classAffinity;
  const dist = new Map\(\);
  dist.set\(srcId, 0\);
  const queue = [srcId];
  let head = 0;
  while \(head < queue.length\) {
    const cur = queue[head++];
    const d = dist.get\(cur\);
    for \(const nb of adj.get\(cur\)\) {
      if \(dist.has\(nb\)\) continue;
      // Block foreign start nodes: we can VISIT them \(record distance\)
      // but we do NOT expand through them.
      const nbNode = nodeById.get\(nb\);
      dist.set\(nb, d + 1\);
      const isForeignStart = nbNode.type === 'start' && nbNode.classAffinity !== srcClass;
      if \(!isForeignStart\) {
        queue.push\(nb\);
      }
    }
  }
  return dist;
}

// ── 4 & 5. Connectivity check + max distance ────────────

console.log\('\\n=== 4. BFS connectivity \(≤60 steps, no foreign-start passthrough\) ==='\);

let globalMax = 0;
let globalMaxPair = ['', ''];
let allReachable = true;
let unreachablePairs = 0;
let pairsOver60 = 0;

const nodeList = nodes.map\(n => n.id\);
const N = nodeList.length;

for \(let i = 0; i < N; i++\) {
  const srcId = nodeList[i];
  const dist = bfsConstrained\(srcId\);

  for \(let j = 0; j < N; j++\) {
    if \(i === j\) continue;
    const dstId = nodeList[j];
    if \(!dist.has\(dstId\)\) {
      allReachable = false;
      unreachablePairs++;
    } else {
      const d = dist.get\(dstId\);
      if \(d > 60\) pairsOver60++;
      if \(d > globalMax\) {
        globalMax = d;
        globalMaxPair = [nodeById.get\(srcId\).nodeId, nodeById.get\(dstId\).nodeId];
      }
    }
  }
}

if \(allReachable && pairsOver60 === 0\) {
  console.log\('  YES — every node can reach every other node within 60 steps.'\);
} else {
  if \(!allReachable\) {
    console.log\(`  NO — ${unreachablePairs} ordered pairs are completely unreachable.`\);
  }
  if \(pairsOver60 > 0\) {
    console.log\(`  NO — ${pairsOver60} ordered pairs exceed 60 steps.`\);
  }
}

console.log\(`\\n=== 5. Max BFS distance \(no foreign-start passthrough\) ===`\);
console.log\(`  ${globalMax} steps`\);
console.log\(`  Between: ${globalMaxPair[0]}  →  ${globalMaxPair[1]}`\);
SCRIPT_EOF)
